    public class Контрагенти_Pointer : DirectoryPointer
    {
        public Контрагенти_Pointer() : base(Config.Kernel, "tab_a08", Контрагенти_Const.TYPE) => base.Init(new UniqueID());
        public Контрагенти_Pointer(object? uid) : base(Config.Kernel, "tab_a08", Контрагенти_Const.TYPE) => base.Init(new UniqueID(uid));
        public Контрагенти_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_a08", Контрагенти_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public Контрагенти_Pointer(UniqueID uid) : base(Config.Kernel, "tab_a08", Контрагенти_Const.TYPE) => base.Init(uid);
        public Контрагенти_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_a08", Контрагенти_Const.TYPE) => base.Init(uid, fields);
        public Контрагенти_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_a08", Контрагенти_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public async Task<Контрагенти_Object?> GetDirectoryObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            Контрагенти_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
        public Контрагенти_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(Контрагенти_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [Контрагенти_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{Контрагенти_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(Контрагенти_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        public async Task SetDeletionLabel(bool label = true)
        {
            Контрагенти_Object? obj = await GetDirectoryObject();
              if (obj != null) await Контрагенти_Triggers.SetDeletionLabel(obj, label);
            
            await base.BaseDeletionLabel(label);
        }
        public Контрагенти_Pointer GetEmptyPointer() => new();
    }
    
    public class Контрагенти_Select : DirectorySelect
    {
        public Контрагенти_Select() : base(Config.Kernel, "tab_a08") { }        
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new Контрагенти_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public Контрагенти_Pointer? Current { get; private set; }
        
        public async Task<Контрагенти_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new Контрагенти_Pointer(pointer) : new Контрагенти_Pointer();
        }
        
        public async Task<List<Контрагенти_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<Контрагенти_Pointer> directoryPointerList = [];
            foreach (var directoryPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                directoryPointerList.Add(new Контрагенти_Pointer(directoryPointer.UniqueID, directoryPointer.Fields));
            return directoryPointerList;
        }
    }

    
    
    public class Контрагенти_Контакти_TablePart : DirectoryTablePart
    {
        public Контрагенти_Контакти_TablePart(Контрагенти_Object owner) : base(Config.Kernel, "tab_a09",
             ["col_d2", "col_d8", "col_d7", "col_d3", "col_d5", "col_d4", "col_d6", "col_a1", "col_a2", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_a09";
        
        public const string Тип = "col_d2";
        public const string Телефон = "col_d8";
        public const string ЕлектроннаПошта = "col_d7";
        public const string Країна = "col_d3";
        public const string Область = "col_d5";
        public const string Район = "col_d4";
        public const string Місто = "col_d6";
        public const string Значення = "col_a1";
        public const string НомерРядка = "col_a2";

        public Контрагенти_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    Тип = (fieldValue["col_d2"] != DBNull.Value) ? (Перелічення.ТипиКонтактноїІнформації)fieldValue["col_d2"] : 0,
                    Телефон = fieldValue["col_d8"].ToString() ?? "",
                    ЕлектроннаПошта = fieldValue["col_d7"].ToString() ?? "",
                    Країна = fieldValue["col_d3"].ToString() ?? "",
                    Область = fieldValue["col_d5"].ToString() ?? "",
                    Район = fieldValue["col_d4"].ToString() ?? "",
                    Місто = fieldValue["col_d6"].ToString() ?? "",
                    Значення = fieldValue["col_a1"].ToString() ?? "",
                    НомерРядка = (fieldValue["col_a2"] != DBNull.Value) ? (int)fieldValue["col_a2"] : 0,
                    
                };
                Records.Add(record);
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_a08"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            
                
            await base.BaseBeginTransaction();

            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);
            
            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_d2", (int)record.Тип},
                    {"col_d8", record.Телефон},
                    {"col_d7", record.ЕлектроннаПошта},
                    {"col_d3", record.Країна},
                    {"col_d5", record.Область},
                    {"col_d4", record.Район},
                    {"col_d6", record.Місто},
                    {"col_a1", record.Значення},
                    {"col_a2", record.НомерРядка},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
                
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    Тип = original.Тип,
                    Телефон = original.Телефон,
                    ЕлектроннаПошта = original.ЕлектроннаПошта,
                    Країна = original.Країна,
                    Область = original.Область,
                    Район = original.Район,
                    Місто = original.Місто,
                    Значення = original.Значення,
                    НомерРядка = original.НомерРядка,
                    
                });
            }

            return copy;
        }
        
        public class Record : DirectoryTablePartRecord
        {
            public Перелічення.ТипиКонтактноїІнформації Тип { get; set; } = 0;
            public string Телефон { get; set; } = "";
            public string ЕлектроннаПошта { get; set; } = "";
            public string Країна { get; set; } = "";
            public string Область { get; set; } = "";
            public string Район { get; set; } = "";
            public string Місто { get; set; } = "";
            public string Значення { get; set; } = "";
            public int НомерРядка { get; set; } = 0;
            
        }
    }
      
    
