                    Ч = fieldValue["col_d4"].ToString() ?? "",
                    Ш = fieldValue["col_d5"].ToString() ?? "",
                    Щ = fieldValue["col_d6"].ToString() ?? "",
                    Ь = fieldValue["col_d7"].ToString() ?? "",
                    Ю = fieldValue["col_d8"].ToString() ?? "",
                    Я = fieldValue["col_d9"].ToString() ?? "",
                    
                };
                Records.Add(record);
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_b04"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            
                
            await base.BaseBeginTransaction();

            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);
            
            
            foreach (Record record in Records)
            {
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a2", record.А},
                    {"col_a5", record.Б},
                    {"col_a6", record.В},
                    {"col_a7", record.Г},
                    {"col_a8", record.Ґ},
                    {"col_a9", record.Д},
                    {"col_b1", record.Е},
                    {"col_b2", record.Є},
                    {"col_b3", record.Ж},
                    {"col_b4", record.З},
                    {"col_b5", record.И},
                    {"col_b6", record.І},
                    {"col_b7", record.Ї},
                    {"col_b8", record.Й},
                    {"col_b9", record.К},
                    {"col_c1", record.Л},
                    {"col_c2", record.М},
                    {"col_c3", record.Н},
                    {"col_c4", record.О},
                    {"col_c5", record.П},
                    {"col_c6", record.Р},
                    {"col_c7", record.С},
                    {"col_c8", record.Т},
                    {"col_c9", record.У},
                    {"col_d1", record.Ф},
                    {"col_d2", record.Х},
                    {"col_d3", record.Ц},
                    {"col_d4", record.Ч},
                    {"col_d5", record.Ш},
                    {"col_d6", record.Щ},
                    {"col_d7", record.Ь},
                    {"col_d8", record.Ю},
                    {"col_d9", record.Я},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
                
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
