                xmlWriter.WriteValue(obj.СумаДокументу);
              
            xmlWriter.WriteEndElement(); //СумаДокументу
            xmlWriter.WriteStartElement("Склад");
            xmlWriter.WriteAttributeString("type", "pointer");
            
