    public class ПрихіднийКасовийОрдер_Object : DocumentObject
    {
        public ПрихіднийКасовийОрдер_Object() : base(Config.Kernel, "tab_a44", ПрихіднийКасовийОрдер_Const.TYPE,
             ["docname", "docnomer", "docdate", "col_h8", "col_h9", "col_i1", "col_i2", "col_i3", "col_i4", "col_a6", "col_i5", "col_i6", "col_a1", "col_a2", "col_a4", "col_a3", "col_a5", "col_a7", "col_a8", "col_a9", ], true)
        {
            
                //Табличні частини
                РозшифруванняПлатежу_TablePart = new ПрихіднийКасовийОрдер_РозшифруванняПлатежу_TablePart(this);
                Проводки_TablePart = new ПрихіднийКасовийОрдер_Проводки_TablePart(this);
                
        }
        
        public async Task New()
        {
            BaseNew();
            Caption = ПрихіднийКасовийОрдер_Const.FULLNAME + " *";
            
                await ПрихіднийКасовийОрдер_Triggers.New(this);
              
        }

        public async Task<bool> Read(UniqueID uid, bool readAllTablePart = false)
        {
            if (await BaseRead(uid))
            {
                Назва = base.FieldValue["docname"].ToString() ?? "";
                НомерДок = base.FieldValue["docnomer"].ToString() ?? "";
                ДатаДок = (base.FieldValue["docdate"] != DBNull.Value) ? DateTime.Parse(base.FieldValue["docdate"].ToString() ?? DateTime.MinValue.ToString()) : DateTime.MinValue;
                Організація = new Довідники.Організації_Pointer(base.FieldValue["col_h8"]);
                Каса = new Довідники.Каси_Pointer(base.FieldValue["col_h9"]);
                СумаДокументу = (base.FieldValue["col_i1"] != DBNull.Value) ? (decimal)base.FieldValue["col_i1"] : 0;
                ГосподарськаОперація = (base.FieldValue["col_i2"] != DBNull.Value) ? (Перелічення.ГосподарськіОперації)base.FieldValue["col_i2"] : 0;
                Основа = (base.FieldValue["col_i3"] != DBNull.Value) ? (UuidAndText)base.FieldValue["col_i3"] : new UuidAndText();
                Контрагент = new Довідники.Контрагенти_Pointer(base.FieldValue["col_i4"]);
                Договір = new Довідники.ДоговориКонтрагентів_Pointer(base.FieldValue["col_a6"]);
                БанківськийРахунок = new Довідники.БанківськіРахункиОрганізацій_Pointer(base.FieldValue["col_i5"]);
                Валюта = new Довідники.Валюти_Pointer(base.FieldValue["col_i6"]);
                СтаттяРухуКоштів = new Довідники.СтаттяРухуКоштів_Pointer(base.FieldValue["col_a1"]);
                КасаВідправник = new Довідники.Каси_Pointer(base.FieldValue["col_a2"]);
                Курс = (base.FieldValue["col_a4"] != DBNull.Value) ? (decimal)base.FieldValue["col_a4"] : 0;
                Коментар = base.FieldValue["col_a3"].ToString() ?? "";
                Автор = new Довідники.Користувачі_Pointer(base.FieldValue["col_a5"]);
                КлючовіСловаДляПошуку = base.FieldValue["col_a7"].ToString() ?? "";
                ДокументБухгалтерськаОперація = new Документи.БухгалтерськаОперація_Pointer(base.FieldValue["col_a8"]);
                ВідобразитиВБухгалтерськомуОбліку = (base.FieldValue["col_a9"] != DBNull.Value) ? (bool)base.FieldValue["col_a9"] : false;
                
                BaseClear();
                
                if (readAllTablePart)
                {
                    
                    await РозшифруванняПлатежу_TablePart.Read();
                    await Проводки_TablePart.Read();
                }
                
                Caption = string.Join(", ", [Назва, ]);
                return true;
            }
            else
                return false;
        }
        
        public async Task<bool> Save()
        {
            
                await ПрихіднийКасовийОрдер_Triggers.BeforeSave(this);
            base.FieldValue["docname"] = Назва;
            base.FieldValue["docnomer"] = НомерДок;
            base.FieldValue["docdate"] = ДатаДок;
            base.FieldValue["col_h8"] = Організація.UniqueID.UGuid;
            base.FieldValue["col_h9"] = Каса.UniqueID.UGuid;
            base.FieldValue["col_i1"] = СумаДокументу;
            base.FieldValue["col_i2"] = (int)ГосподарськаОперація;
            base.FieldValue["col_i3"] = Основа;
            base.FieldValue["col_i4"] = Контрагент.UniqueID.UGuid;
            base.FieldValue["col_a6"] = Договір.UniqueID.UGuid;
            base.FieldValue["col_i5"] = БанківськийРахунок.UniqueID.UGuid;
            base.FieldValue["col_i6"] = Валюта.UniqueID.UGuid;
            base.FieldValue["col_a1"] = СтаттяРухуКоштів.UniqueID.UGuid;
            base.FieldValue["col_a2"] = КасаВідправник.UniqueID.UGuid;
            base.FieldValue["col_a4"] = Курс;
            base.FieldValue["col_a3"] = Коментар;
            base.FieldValue["col_a5"] = Автор.UniqueID.UGuid;
            base.FieldValue["col_a7"] = КлючовіСловаДляПошуку;
            base.FieldValue["col_a8"] = ДокументБухгалтерськаОперація.UniqueID.UGuid;
            base.FieldValue["col_a9"] = ВідобразитиВБухгалтерськомуОбліку;
            
            bool result = await BaseSave();
            if (result)
            {
                
                await BaseWriteFullTextSearch(GetBasis(), [Назва, НомерДок, Коментар, КлючовіСловаДляПошуку, ]);
                
            }
            Caption = string.Join(", ", [Назва, ]);
            return result;
        }

        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            
            await BaseAddIgnoreDocumentList();
            bool spend = await ПрихіднийКасовийОрдер_SpendTheDocument.Spend(this);
            if (!spend) await ClearRegAccum();
            await BaseSpend(spend, spend ? spendDate : DateTime.MinValue);
            await BaseRemoveIgnoreDocumentList();
            return spend;
                
        }

        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.РозрахункиЗКлієнтами_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РозрахункиЗПостачальниками_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РухКоштів_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          

        public async Task ClearSpendTheDocument()
        {
            await ClearRegAccum();
            
            await ПрихіднийКасовийОрдер_SpendTheDocument.Clear(this);
            
            await BaseSpend(false, DateTime.MinValue);
        }

        public async Task<ПрихіднийКасовийОрдер_Object> Copy(bool copyTableParts = false)
        {
            ПрихіднийКасовийОрдер_Object copy = new()
            {
                Назва = Назва,
                НомерДок = НомерДок,
                ДатаДок = ДатаДок,
                Організація = Організація.Copy(),
                Каса = Каса.Copy(),
                СумаДокументу = СумаДокументу,
                ГосподарськаОперація = ГосподарськаОперація,
                Основа = Основа.Copy(),
                Контрагент = Контрагент.Copy(),
                Договір = Договір.Copy(),
                БанківськийРахунок = БанківськийРахунок.Copy(),
                Валюта = Валюта.Copy(),
                СтаттяРухуКоштів = СтаттяРухуКоштів.Copy(),
                КасаВідправник = КасаВідправник.Copy(),
                Курс = Курс,
                Коментар = Коментар,
                Автор = Автор.Copy(),
                КлючовіСловаДляПошуку = КлючовіСловаДляПошуку,
                ДокументБухгалтерськаОперація = ДокументБухгалтерськаОперація.Copy(),
                ВідобразитиВБухгалтерськомуОбліку = ВідобразитиВБухгалтерськомуОбліку,
                
            };
            
            if (copyTableParts)
            {
            
                //РозшифруванняПлатежу - Таблична частина
                await РозшифруванняПлатежу_TablePart.Read();
                copy.РозшифруванняПлатежу_TablePart.Records = РозшифруванняПлатежу_TablePart.Copy();
            
                //Проводки - Таблична частина
                await Проводки_TablePart.Read();
                copy.Проводки_TablePart.Records = Проводки_TablePart.Copy();
            
            }
            

            await copy.New();
            
                await ПрихіднийКасовийОрдер_Triggers.Copying(copy, this);      
            
            return copy;
        }

        public async Task SetDeletionLabel(bool label = true)
        {
            
            await ClearSpendTheDocument();
            await base.BaseDeletionLabel(label);
        }

        public async Task Delete()
        {
            
            await ClearSpendTheDocument();
            await base.BaseDelete(["tab_a47", "tab_c32", ]);
        }
        
