    public class РозхіднийКасовийОрдер_Pointer : DocumentPointer
    {
        public РозхіднийКасовийОрдер_Pointer() : base(Config.Kernel, "tab_a48", РозхіднийКасовийОрдер_Const.TYPE) => base.Init(new UniqueID());
        public РозхіднийКасовийОрдер_Pointer(object? uid) : base(Config.Kernel, "tab_a48", РозхіднийКасовийОрдер_Const.TYPE) => base.Init(new UniqueID(uid));
        public РозхіднийКасовийОрдер_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_a48", РозхіднийКасовийОрдер_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public РозхіднийКасовийОрдер_Pointer(UniqueID uid) : base(Config.Kernel, "tab_a48", РозхіднийКасовийОрдер_Const.TYPE) => base.Init(uid);
        public РозхіднийКасовийОрдер_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_a48", РозхіднийКасовийОрдер_Const.TYPE) => base.Init(uid, fields);
        public РозхіднийКасовийОрдер_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_a48", РозхіднийКасовийОрдер_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(РозхіднийКасовийОрдер_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [РозхіднийКасовийОрдер_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{РозхіднийКасовийОрдер_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(РозхіднийКасовийОрдер_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            РозхіднийКасовийОрдер_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            РозхіднийКасовийОрдер_Object? obj = await GetDocumentObject();
            if (obj != null) await obj.ClearSpendTheDocument();
                
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.РозрахункиЗКлієнтами_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РозрахункиЗПостачальниками_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РухКоштів_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          
        public async Task SetDeletionLabel(bool label = true)
        {
          РозхіднийКасовийОрдер_Object? obj = await GetDocumentObject();
            if (obj == null) return;
            
            if (label) await obj.ClearSpendTheDocument();
            
          await base.BaseDeletionLabel(label);
        }
        public РозхіднийКасовийОрдер_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public РозхіднийКасовийОрдер_Pointer GetEmptyPointer() => new();
        public async Task<РозхіднийКасовийОрдер_Object?> GetDocumentObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            РозхіднийКасовийОрдер_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
    }

    public class РозхіднийКасовийОрдер_Select : DocumentSelect
    {		
        public РозхіднийКасовийОрдер_Select() : base(Config.Kernel, "tab_a48") { }
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new РозхіднийКасовийОрдер_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public РозхіднийКасовийОрдер_Pointer? Current { get; private set; }

        public async Task<РозхіднийКасовийОрдер_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new РозхіднийКасовийОрдер_Pointer(pointer) : new РозхіднийКасовийОрдер_Pointer();
        }
        
        public async Task<List<РозхіднийКасовийОрдер_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<РозхіднийКасовийОрдер_Pointer> documentPointerList = [];
            foreach (var documentPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                documentPointerList.Add(new РозхіднийКасовийОрдер_Pointer(documentPointer.UniqueID, documentPointer.Fields));
            return documentPointerList;
        }
    }

      
    
    public class РозхіднийКасовийОрдер_РозшифруванняПлатежу_TablePart : DocumentTablePart
    {
        public РозхіднийКасовийОрдер_РозшифруванняПлатежу_TablePart(РозхіднийКасовийОрдер_Object owner) : base(Config.Kernel, "tab_a49",
             ["col_a1", "col_l4", "col_l5", "col_l6", "col_l7", "col_l8", "col_l9", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_a49";
        
        public const string НомерРядка = "col_a1";
        public const string Замовлення = "col_l4";
        public const string Сума = "col_l5";
        public const string ВалютаВзаєморозрахунків = "col_l6";
        public const string Підрозділ = "col_l7";
        public const string Коментар = "col_l8";
        public const string Організація = "col_l9";

        public РозхіднийКасовийОрдер_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.Валюти_Pointer.GetJoin(QuerySelect, ВалютаВзаєморозрахунків, $"{TABLE}", "join_tab_4", "ВалютаВзаєморозрахунків");
                  
                      /* pointer */
                      Довідники.СтруктураПідприємства_Pointer.GetJoin(QuerySelect, Підрозділ, $"{TABLE}", "join_tab_5", "Підрозділ");
                  
                      /* pointer */
                      Довідники.Організації_Pointer.GetJoin(QuerySelect, Організація, $"{TABLE}", "join_tab_7", "Організація");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_a1"] != DBNull.Value) ? (int)fieldValue["col_a1"] : 0,
                    Замовлення = fieldValue["col_l4"].ToString() ?? "",
                    Сума = (fieldValue["col_l5"] != DBNull.Value) ? (decimal)fieldValue["col_l5"] : 0,
                    ВалютаВзаєморозрахунків = new Довідники.Валюти_Pointer(fieldValue["col_l6"]),
                    Підрозділ = new Довідники.СтруктураПідприємства_Pointer(fieldValue["col_l7"]),
                    Коментар = fieldValue["col_l8"].ToString() ?? "",
                    Організація = new Довідники.Організації_Pointer(fieldValue["col_l9"]),
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.ВалютаВзаєморозрахунків.Name = ItemValue["ВалютаВзаєморозрахунків"];
                      record.Підрозділ.Name = ItemValue["Підрозділ"];
                      record.Організація.Name = ItemValue["Організація"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_a48"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a1", record.НомерРядка},
                    {"col_l4", record.Замовлення},
                    {"col_l5", record.Сума},
                    {"col_l6", record.ВалютаВзаєморозрахунків.UniqueID.UGuid},
                    {"col_l7", record.Підрозділ.UniqueID.UGuid},
                    {"col_l8", record.Коментар},
                    {"col_l9", record.Організація.UniqueID.UGuid},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Замовлення = original.Замовлення,
                    Сума = original.Сума,
                    ВалютаВзаєморозрахунків = original.ВалютаВзаєморозрахунків.Copy(),
                    Підрозділ = original.Підрозділ.Copy(),
                    Коментар = original.Коментар,
                    Організація = original.Організація.Copy(),
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public string Замовлення { get; set; } = "";
            public decimal Сума { get; set; } = 0;
            public Довідники.Валюти_Pointer ВалютаВзаєморозрахунків { get; set; } = new Довідники.Валюти_Pointer();
            public Довідники.СтруктураПідприємства_Pointer Підрозділ { get; set; } = new Довідники.СтруктураПідприємства_Pointer();
            public string Коментар { get; set; } = "";
            public Довідники.Організації_Pointer Організація { get; set; } = new Довідники.Організації_Pointer();
            
        }
    }
      
    
    public class РозхіднийКасовийОрдер_Проводки_TablePart : DocumentTablePart
    {
        public РозхіднийКасовийОрдер_Проводки_TablePart(РозхіднийКасовийОрдер_Object owner) : base(Config.Kernel, "tab_c33",
             ["col_a1", "col_a2", "col_a3", "col_a4", "col_a5", "col_a6", "col_a7", "col_a8", ])
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_c33";
        
        public const string НомерРядка = "col_a1";
        public const string Рахунок = "col_a2";
        public const string Аналітика1 = "col_a3";
        public const string Аналітика2 = "col_a4";
        public const string Аналітика3 = "col_a5";
        public const string Податки = "col_a6";
        public const string Дебет = "col_a7";
        public const string Кредит = "col_a8";

        public РозхіднийКасовийОрдер_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.ПланРахунків_Pointer.GetJoin(QuerySelect, Рахунок, $"{TABLE}", "join_tab_2", "Рахунок");
                  
                      /* composite_pointer */
                      QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({TABLE}.{Аналітика1})", "Аналітика1"));
                  
                      /* composite_pointer */
                      QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({TABLE}.{Аналітика2})", "Аналітика2"));
                  
                      /* composite_pointer */
                      QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({TABLE}.{Аналітика3})", "Аналітика3"));
                  
                      /* pointer */
                      Довідники.ВидиПодатків_Pointer.GetJoin(QuerySelect, Податки, $"{TABLE}", "join_tab_6", "Податки");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_a1"] != DBNull.Value) ? (int)fieldValue["col_a1"] : 0,
                    Рахунок = new Довідники.ПланРахунків_Pointer(fieldValue["col_a2"]),
                    Аналітика1 = (fieldValue["col_a3"] != DBNull.Value) ? (UuidAndText)fieldValue["col_a3"] : new UuidAndText(),
                    Аналітика2 = (fieldValue["col_a4"] != DBNull.Value) ? (UuidAndText)fieldValue["col_a4"] : new UuidAndText(),
                    Аналітика3 = (fieldValue["col_a5"] != DBNull.Value) ? (UuidAndText)fieldValue["col_a5"] : new UuidAndText(),
                    Податки = new Довідники.ВидиПодатків_Pointer(fieldValue["col_a6"]),
                    Дебет = (fieldValue["col_a7"] != DBNull.Value) ? (decimal)fieldValue["col_a7"] : 0,
                    Кредит = (fieldValue["col_a8"] != DBNull.Value) ? (decimal)fieldValue["col_a8"] : 0,
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.Рахунок.Name = ItemValue["Рахунок"];
                      record.Аналітика1.Name = ItemValue["Аналітика1"];
                      record.Аналітика2.Name = ItemValue["Аналітика2"];
                      record.Аналітика3.Name = ItemValue["Аналітика3"];
                      record.Податки.Name = ItemValue["Податки"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_a48"))
                throw new Exception("Owner not exist");
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a1", record.НомерРядка},
                    {"col_a2", record.Рахунок.UniqueID.UGuid},
                    {"col_a3", record.Аналітика1},
                    {"col_a4", record.Аналітика2},
                    {"col_a5", record.Аналітика3},
                    {"col_a6", record.Податки.UniqueID.UGuid},
                    {"col_a7", record.Дебет},
                    {"col_a8", record.Кредит},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await РозхіднийКасовийОрдер_Проводки_Triggers.AfterSave(Owner, this);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Рахунок = original.Рахунок.Copy(),
                    Аналітика1 = original.Аналітика1.Copy(),
                    Аналітика2 = original.Аналітика2.Copy(),
                    Аналітика3 = original.Аналітика3.Copy(),
                    Податки = original.Податки.Copy(),
                    Дебет = original.Дебет,
                    Кредит = original.Кредит,
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public Довідники.ПланРахунків_Pointer Рахунок { get; set; } = new Довідники.ПланРахунків_Pointer();
            public UuidAndText Аналітика1 { get; set; } = new UuidAndText();
