    public class ПереміщенняТоварів_Pointer : DocumentPointer
    {
        public ПереміщенняТоварів_Pointer() : base(Config.Kernel, "tab_a31", ПереміщенняТоварів_Const.TYPE) => base.Init(new UniqueID());
        public ПереміщенняТоварів_Pointer(object? uid) : base(Config.Kernel, "tab_a31", ПереміщенняТоварів_Const.TYPE) => base.Init(new UniqueID(uid));
        public ПереміщенняТоварів_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_a31", ПереміщенняТоварів_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public ПереміщенняТоварів_Pointer(UniqueID uid) : base(Config.Kernel, "tab_a31", ПереміщенняТоварів_Const.TYPE) => base.Init(uid);
        public ПереміщенняТоварів_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_a31", ПереміщенняТоварів_Const.TYPE) => base.Init(uid, fields);
        public ПереміщенняТоварів_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_a31", ПереміщенняТоварів_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(ПереміщенняТоварів_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [ПереміщенняТоварів_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{ПереміщенняТоварів_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(ПереміщенняТоварів_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            ПереміщенняТоварів_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            ПереміщенняТоварів_Object? obj = await GetDocumentObject();
            if (obj != null) await obj.ClearSpendTheDocument();
                
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.ТовариНаСкладах_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.ВільніЗалишки_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.ПартіїТоварів_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          
        public async Task SetDeletionLabel(bool label = true)
        {
          ПереміщенняТоварів_Object? obj = await GetDocumentObject();
            if (obj == null) return;
            
            if (label) await obj.ClearSpendTheDocument();
            
          await base.BaseDeletionLabel(label);
        }
        public ПереміщенняТоварів_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public ПереміщенняТоварів_Pointer GetEmptyPointer() => new();
        public async Task<ПереміщенняТоварів_Object?> GetDocumentObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            ПереміщенняТоварів_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
    }

    public class ПереміщенняТоварів_Select : DocumentSelect
    {		
        public ПереміщенняТоварів_Select() : base(Config.Kernel, "tab_a31") { }
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new ПереміщенняТоварів_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public ПереміщенняТоварів_Pointer? Current { get; private set; }

        public async Task<ПереміщенняТоварів_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new ПереміщенняТоварів_Pointer(pointer) : new ПереміщенняТоварів_Pointer();
        }
        
        public async Task<List<ПереміщенняТоварів_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<ПереміщенняТоварів_Pointer> documentPointerList = [];
            foreach (var documentPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                documentPointerList.Add(new ПереміщенняТоварів_Pointer(documentPointer.UniqueID, documentPointer.Fields));
            return documentPointerList;
        }
    }

      
    
    public class ПереміщенняТоварів_Товари_TablePart : DocumentTablePart
    {
        public ПереміщенняТоварів_Товари_TablePart(ПереміщенняТоварів_Object owner) : base(Config.Kernel, "tab_a50",
             ["col_b8", "col_b3", "col_b4", "col_a1", "col_b5", "col_b6", "col_b7", "col_a2", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_a50";
        
        public const string НомерРядка = "col_b8";
        public const string Номенклатура = "col_b3";
        public const string ХарактеристикаНоменклатури = "col_b4";
        public const string Серія = "col_a1";
        public const string Пакування = "col_b5";
        public const string КількістьУпаковок = "col_b6";
        public const string Кількість = "col_b7";
        public const string Партія = "col_a2";

        public ПереміщенняТоварів_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.Номенклатура_Pointer.GetJoin(QuerySelect, Номенклатура, $"{TABLE}", "join_tab_2", "Номенклатура");
                  
                      /* pointer */
                      Довідники.ХарактеристикиНоменклатури_Pointer.GetJoin(QuerySelect, ХарактеристикаНоменклатури, $"{TABLE}", "join_tab_3", "ХарактеристикаНоменклатури");
                  
                      /* pointer */
                      Довідники.СеріїНоменклатури_Pointer.GetJoin(QuerySelect, Серія, $"{TABLE}", "join_tab_4", "Серія");
                  
                      /* pointer */
                      Довідники.ПакуванняОдиниціВиміру_Pointer.GetJoin(QuerySelect, Пакування, $"{TABLE}", "join_tab_5", "Пакування");
                  
                      /* pointer */
