        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            
            await BaseAddIgnoreDocumentList();
            bool spend = await ПоверненняТоварівВідКлієнта_SpendTheDocument.Spend(this);
            if (!spend) await ClearRegAccum();
            await BaseSpend(spend, spend ? spendDate : DateTime.MinValue);
            await BaseRemoveIgnoreDocumentList();
            return spend;
                
        }

        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.ТовариНаСкладах_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РозрахункиЗКлієнтами_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.ВільніЗалишки_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.ПартіїТоварів_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.Продажі_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          

        public async Task ClearSpendTheDocument()
        {
            await ClearRegAccum();
            
            await ПоверненняТоварівВідКлієнта_SpendTheDocument.Clear(this);
            
            await BaseSpend(false, DateTime.MinValue);
        }

        public async Task<ПоверненняТоварівВідКлієнта_Object> Copy(bool copyTableParts = false)
        {
            ПоверненняТоварівВідКлієнта_Object copy = new()
            {
                Назва = Назва,
                НомерДок = НомерДок,
                ДатаДок = ДатаДок,
                Організація = Організація.Copy(),
                Валюта = Валюта.Copy(),
                СумаДокументу = СумаДокументу,
                Склад = Склад.Copy(),
                Підрозділ = Підрозділ.Copy(),
                Менеджер = Менеджер.Copy(),
                ДокументПродажу = ДокументПродажу.Copy(),
                ГосподарськаОперація = ГосподарськаОперація,
                Договір = Договір.Copy(),
                ПричинаПовернення = ПричинаПовернення,
                Контрагент = Контрагент.Copy(),
                Каса = Каса.Copy(),
                Основа = Основа.Copy(),
                Коментар = Коментар,
                Автор = Автор.Copy(),
                КлючовіСловаДляПошуку = КлючовіСловаДляПошуку,
                ДокументБухгалтерськаОперація = ДокументБухгалтерськаОперація.Copy(),
                ВідобразитиВБухгалтерськомуОбліку = ВідобразитиВБухгалтерськомуОбліку,
                
            };
            
            if (copyTableParts)
            {
            
                //Товари - Таблична частина
                await Товари_TablePart.Read();
                copy.Товари_TablePart.Records = Товари_TablePart.Copy();
            
                //Проводки - Таблична частина
                await Проводки_TablePart.Read();
                copy.Проводки_TablePart.Records = Проводки_TablePart.Copy();
            
            }
            

            await copy.New();
            
                await ПоверненняТоварівВідКлієнта_Triggers.Copying(copy, this);      
            
            return copy;
        }

