    public class АктВиконанихРобіт_Проводки_TablePart : DocumentTablePart
    {
        public АктВиконанихРобіт_Проводки_TablePart(АктВиконанихРобіт_Object owner) : base(Config.Kernel, "tab_c26",
             ["col_a1", "col_a2", "col_a3", "col_a4", "col_a5", "col_a6", "col_a7", "col_a8", ])
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_c26";
        
        public const string НомерРядка = "col_a1";
        public const string Рахунок = "col_a2";
        public const string Аналітика1 = "col_a3";
        public const string Аналітика2 = "col_a4";
        public const string Аналітика3 = "col_a5";
        public const string Податки = "col_a6";
        public const string Дебет = "col_a7";
        public const string Кредит = "col_a8";

        public АктВиконанихРобіт_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.ПланРахунків_Pointer.GetJoin(QuerySelect, Рахунок, $"{TABLE}", "join_tab_2", "Рахунок");
                  
                      /* composite_pointer */
                      QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({TABLE}.{Аналітика1})", "Аналітика1"));
                  
                      /* composite_pointer */
                      QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({TABLE}.{Аналітика2})", "Аналітика2"));
                  
                      /* composite_pointer */
                      QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({TABLE}.{Аналітика3})", "Аналітика3"));
                  
                      /* pointer */
                      Довідники.ВидиПодатків_Pointer.GetJoin(QuerySelect, Податки, $"{TABLE}", "join_tab_6", "Податки");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_a1"] != DBNull.Value) ? (int)fieldValue["col_a1"] : 0,
                    Рахунок = new Довідники.ПланРахунків_Pointer(fieldValue["col_a2"]),
                    Аналітика1 = (fieldValue["col_a3"] != DBNull.Value) ? (UuidAndText)fieldValue["col_a3"] : new UuidAndText(),
                    Аналітика2 = (fieldValue["col_a4"] != DBNull.Value) ? (UuidAndText)fieldValue["col_a4"] : new UuidAndText(),
                    Аналітика3 = (fieldValue["col_a5"] != DBNull.Value) ? (UuidAndText)fieldValue["col_a5"] : new UuidAndText(),
                    Податки = new Довідники.ВидиПодатків_Pointer(fieldValue["col_a6"]),
                    Дебет = (fieldValue["col_a7"] != DBNull.Value) ? (decimal)fieldValue["col_a7"] : 0,
                    Кредит = (fieldValue["col_a8"] != DBNull.Value) ? (decimal)fieldValue["col_a8"] : 0,
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.Рахунок.Name = ItemValue["Рахунок"];
                      record.Аналітика1.Name = ItemValue["Аналітика1"];
                      record.Аналітика2.Name = ItemValue["Аналітика2"];
                      record.Аналітика3.Name = ItemValue["Аналітика3"];
                      record.Податки.Name = ItemValue["Податки"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_a81"))
                throw new Exception("Owner not exist");
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a1", record.НомерРядка},
                    {"col_a2", record.Рахунок.UniqueID.UGuid},
                    {"col_a3", record.Аналітика1},
                    {"col_a4", record.Аналітика2},
                    {"col_a5", record.Аналітика3},
                    {"col_a6", record.Податки.UniqueID.UGuid},
                    {"col_a7", record.Дебет},
                    {"col_a8", record.Кредит},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await АктВиконанихРобіт_Проводки_Triggers.AfterSave(Owner, this);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Рахунок = original.Рахунок.Copy(),
                    Аналітика1 = original.Аналітика1.Copy(),
                    Аналітика2 = original.Аналітика2.Copy(),
                    Аналітика3 = original.Аналітика3.Copy(),
                    Податки = original.Податки.Copy(),
                    Дебет = original.Дебет,
                    Кредит = original.Кредит,
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public Довідники.ПланРахунків_Pointer Рахунок { get; set; } = new Довідники.ПланРахунків_Pointer();
            public UuidAndText Аналітика1 { get; set; } = new UuidAndText();
            public UuidAndText Аналітика2 { get; set; } = new UuidAndText();
            public UuidAndText Аналітика3 { get; set; } = new UuidAndText();
            public Довідники.ВидиПодатків_Pointer Податки { get; set; } = new Довідники.ВидиПодатків_Pointer();
            public decimal Дебет { get; set; } = 0;
            public decimal Кредит { get; set; } = 0;
            
        }
    }
      
    
    public static class АктВиконанихРобіт_Export
    {
        public static async Task ToXmlFile(АктВиконанихРобіт_Pointer АктВиконанихРобіт, string pathToSave)
        {
        АктВиконанихРобіт_Object? obj = await АктВиконанихРобіт.GetDocumentObject(true);
            if (obj == null) return;

            XmlWriter xmlWriter = XmlWriter.Create(pathToSave, new XmlWriterSettings() { Indent = true, Encoding = System.Text.Encoding.UTF8 });
            xmlWriter.WriteStartDocument();
            xmlWriter.WriteStartElement("Document");
            xmlWriter.WriteAttributeString("uid", obj.UniqueID.ToString());
            
            xmlWriter.WriteStartElement("Назва");
            xmlWriter.WriteAttributeString("type", "string");
            
                xmlWriter.WriteCData(obj.Назва);
              
            xmlWriter.WriteEndElement(); //Назва
            xmlWriter.WriteStartElement("НомерДок");
            xmlWriter.WriteAttributeString("type", "string");
            
                xmlWriter.WriteCData(obj.НомерДок);
              
            xmlWriter.WriteEndElement(); //НомерДок
            xmlWriter.WriteStartElement("ДатаДок");
            xmlWriter.WriteAttributeString("type", "datetime");
            
                xmlWriter.WriteValue(obj.ДатаДок.ToString("dd.MM.yyyy HH:mm:ss"));
              
            xmlWriter.WriteEndElement(); //ДатаДок
            xmlWriter.WriteStartElement("Валюта");
            xmlWriter.WriteAttributeString("type", "pointer");
            
                    xmlWriter.WriteAttributeString("pointer", "Довідники.Валюти");
                    xmlWriter.WriteAttributeString("uid", obj.Валюта.UniqueID.ToString());
                    xmlWriter.WriteCData(await obj.Валюта.GetPresentation());
                  
            xmlWriter.WriteEndElement(); //Валюта
            xmlWriter.WriteStartElement("Каса");
            xmlWriter.WriteAttributeString("type", "pointer");
            
                    xmlWriter.WriteAttributeString("pointer", "Довідники.Каси");
                    xmlWriter.WriteAttributeString("uid", obj.Каса.UniqueID.ToString());
                    xmlWriter.WriteCData(await obj.Каса.GetPresentation());
                  
            xmlWriter.WriteEndElement(); //Каса
            xmlWriter.WriteStartElement("Контрагент");
            xmlWriter.WriteAttributeString("type", "pointer");
            
                    xmlWriter.WriteAttributeString("pointer", "Довідники.Контрагенти");
                    xmlWriter.WriteAttributeString("uid", obj.Контрагент.UniqueID.ToString());
                    xmlWriter.WriteCData(await obj.Контрагент.GetPresentation());
                  
            xmlWriter.WriteEndElement(); //Контрагент
            xmlWriter.WriteStartElement("Організація");
            xmlWriter.WriteAttributeString("type", "pointer");
            
                    xmlWriter.WriteAttributeString("pointer", "Довідники.Організації");
                    xmlWriter.WriteAttributeString("uid", obj.Організація.UniqueID.ToString());
                    xmlWriter.WriteCData(await obj.Організація.GetPresentation());
                  
            xmlWriter.WriteEndElement(); //Організація
            xmlWriter.WriteStartElement("СумаДокументу");
            xmlWriter.WriteAttributeString("type", "numeric");
            
                xmlWriter.WriteValue(obj.СумаДокументу);
              
            xmlWriter.WriteEndElement(); //СумаДокументу
                /*  Табличні частини */
                xmlWriter.WriteStartElement("TabularParts");
                
                    xmlWriter.WriteStartElement("TablePart");
                    xmlWriter.WriteAttributeString("name", "Послуги");

                    foreach(АктВиконанихРобіт_Послуги_TablePart.Record record in obj.Послуги_TablePart.Records)
                    {
                        xmlWriter.WriteStartElement("row");
                        xmlWriter.WriteAttributeString("uid", record.UID.ToString());
                        
                        xmlWriter.WriteStartElement("НомерРядка");
                        xmlWriter.WriteAttributeString("type", "integer");
                        
                            xmlWriter.WriteValue(record.НомерРядка);
                          
                        xmlWriter.WriteEndElement(); //НомерРядка
                        xmlWriter.WriteStartElement("Номенклатура");
                        xmlWriter.WriteAttributeString("type", "pointer");
                        
                                xmlWriter.WriteAttributeString("pointer", "Довідники.Номенклатура");
                                xmlWriter.WriteAttributeString("uid", record.Номенклатура.UniqueID.ToString());
                                xmlWriter.WriteCData(await record.Номенклатура.GetPresentation());
                              
                        xmlWriter.WriteEndElement(); //Номенклатура
                        xmlWriter.WriteStartElement("ХарактеристикаНоменклатури");
                        xmlWriter.WriteAttributeString("type", "pointer");
                        
                                xmlWriter.WriteAttributeString("pointer", "Довідники.ХарактеристикиНоменклатури");
                                xmlWriter.WriteAttributeString("uid", record.ХарактеристикаНоменклатури.UniqueID.ToString());
                                xmlWriter.WriteCData(await record.ХарактеристикаНоменклатури.GetPresentation());
                              
                        xmlWriter.WriteEndElement(); //ХарактеристикаНоменклатури
                        xmlWriter.WriteStartElement("Кількість");
                        xmlWriter.WriteAttributeString("type", "numeric");
                        
                            xmlWriter.WriteValue(record.Кількість);
                          
                        xmlWriter.WriteEndElement(); //Кількість
                        xmlWriter.WriteStartElement("Ціна");
                        xmlWriter.WriteAttributeString("type", "numeric");
                        
                            xmlWriter.WriteValue(record.Ціна);
                          
                        xmlWriter.WriteEndElement(); //Ціна
                        xmlWriter.WriteStartElement("Сума");
                        xmlWriter.WriteAttributeString("type", "numeric");
                        
                            xmlWriter.WriteValue(record.Сума);
                          
                        xmlWriter.WriteEndElement(); //Сума
                        xmlWriter.WriteEndElement(); //row
                    }

                    xmlWriter.WriteEndElement(); //TablePart
                
                    xmlWriter.WriteStartElement("TablePart");
                    xmlWriter.WriteAttributeString("name", "Проводки");

                    foreach(АктВиконанихРобіт_Проводки_TablePart.Record record in obj.Проводки_TablePart.Records)
                    {
                        xmlWriter.WriteStartElement("row");
                        xmlWriter.WriteAttributeString("uid", record.UID.ToString());
                        
                        xmlWriter.WriteEndElement(); //row
                    }

                    xmlWriter.WriteEndElement(); //TablePart
                
                xmlWriter.WriteEndElement(); //TabularParts
            

            xmlWriter.WriteEndElement(); //root
            xmlWriter.WriteEndDocument();
            xmlWriter.Close();
          
        }
    }

