    public class ВведенняЗалишків_Pointer : DocumentPointer
    {
        public ВведенняЗалишків_Pointer() : base(Config.Kernel, "tab_a83", ВведенняЗалишків_Const.TYPE) => base.Init(new UniqueID());
        public ВведенняЗалишків_Pointer(object? uid) : base(Config.Kernel, "tab_a83", ВведенняЗалишків_Const.TYPE) => base.Init(new UniqueID(uid));
        public ВведенняЗалишків_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_a83", ВведенняЗалишків_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public ВведенняЗалишків_Pointer(UniqueID uid) : base(Config.Kernel, "tab_a83", ВведенняЗалишків_Const.TYPE) => base.Init(uid);
        public ВведенняЗалишків_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_a83", ВведенняЗалишків_Const.TYPE) => base.Init(uid, fields);
        public ВведенняЗалишків_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_a83", ВведенняЗалишків_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(ВведенняЗалишків_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [ВведенняЗалишків_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{ВведенняЗалишків_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(ВведенняЗалишків_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            ВведенняЗалишків_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            ВведенняЗалишків_Object? obj = await GetDocumentObject();
            if (obj != null) await obj.ClearSpendTheDocument();
                
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.ТовариНаСкладах_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РозрахункиЗКлієнтами_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.ВільніЗалишки_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РозрахункиЗПостачальниками_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РухКоштів_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.ПартіїТоварів_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          
        public async Task SetDeletionLabel(bool label = true)
        {
          ВведенняЗалишків_Object? obj = await GetDocumentObject();
            if (obj == null) return;
            
                await ВведенняЗалишків_Triggers.SetDeletionLabel(obj, label);
            
            if (label) await obj.ClearSpendTheDocument();
            
          await base.BaseDeletionLabel(label);
        }
        public ВведенняЗалишків_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public ВведенняЗалишків_Pointer GetEmptyPointer() => new();
        public async Task<ВведенняЗалишків_Object?> GetDocumentObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            ВведенняЗалишків_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
    }

    public class ВведенняЗалишків_Select : DocumentSelect
    {		
        public ВведенняЗалишків_Select() : base(Config.Kernel, "tab_a83") { }
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new ВведенняЗалишків_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public ВведенняЗалишків_Pointer? Current { get; private set; }

        public async Task<ВведенняЗалишків_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new ВведенняЗалишків_Pointer(pointer) : new ВведенняЗалишків_Pointer();
        }
        
        public async Task<List<ВведенняЗалишків_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<ВведенняЗалишків_Pointer> documentPointerList = [];
            foreach (var documentPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                documentPointerList.Add(new ВведенняЗалишків_Pointer(documentPointer.UniqueID, documentPointer.Fields));
            return documentPointerList;
        }
    }

      
    
    public class ВведенняЗалишків_Товари_TablePart : DocumentTablePart
    {
        public ВведенняЗалишків_Товари_TablePart(ВведенняЗалишків_Object owner) : base(Config.Kernel, "tab_a84",
             ["col_e4", "col_d6", "col_d7", "col_a1", "col_d8", "col_d9", "col_e1", "col_e2", "col_e3", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_a84";
        
        public const string НомерРядка = "col_e4";
        public const string Номенклатура = "col_d6";
        public const string ХарактеристикаНоменклатури = "col_d7";
        public const string Серія = "col_a1";
        public const string Пакування = "col_d8";
        public const string КількістьУпаковок = "col_d9";
        public const string Кількість = "col_e1";
        public const string Ціна = "col_e2";
        public const string Сума = "col_e3";

        public ВведенняЗалишків_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.Номенклатура_Pointer.GetJoin(QuerySelect, Номенклатура, $"{TABLE}", "join_tab_2", "Номенклатура");
                  
                      /* pointer */
                      Довідники.ХарактеристикиНоменклатури_Pointer.GetJoin(QuerySelect, ХарактеристикаНоменклатури, $"{TABLE}", "join_tab_3", "ХарактеристикаНоменклатури");
                  
                      /* pointer */
                      Довідники.СеріїНоменклатури_Pointer.GetJoin(QuerySelect, Серія, $"{TABLE}", "join_tab_4", "Серія");
                  
                      /* pointer */
                      Довідники.ПакуванняОдиниціВиміру_Pointer.GetJoin(QuerySelect, Пакування, $"{TABLE}", "join_tab_5", "Пакування");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_e4"] != DBNull.Value) ? (int)fieldValue["col_e4"] : 0,
                    Номенклатура = new Довідники.Номенклатура_Pointer(fieldValue["col_d6"]),
                    ХарактеристикаНоменклатури = new Довідники.ХарактеристикиНоменклатури_Pointer(fieldValue["col_d7"]),
                    Серія = new Довідники.СеріїНоменклатури_Pointer(fieldValue["col_a1"]),
                    Пакування = new Довідники.ПакуванняОдиниціВиміру_Pointer(fieldValue["col_d8"]),
                    КількістьУпаковок = (fieldValue["col_d9"] != DBNull.Value) ? (int)fieldValue["col_d9"] : 0,
                    Кількість = (fieldValue["col_e1"] != DBNull.Value) ? (decimal)fieldValue["col_e1"] : 0,
                    Ціна = (fieldValue["col_e2"] != DBNull.Value) ? (decimal)fieldValue["col_e2"] : 0,
                    Сума = (fieldValue["col_e3"] != DBNull.Value) ? (decimal)fieldValue["col_e3"] : 0,
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.Номенклатура.Name = ItemValue["Номенклатура"];
                      record.ХарактеристикаНоменклатури.Name = ItemValue["ХарактеристикаНоменклатури"];
                      record.Серія.Name = ItemValue["Серія"];
                      record.Пакування.Name = ItemValue["Пакування"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_a83"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_e4", record.НомерРядка},
                    {"col_d6", record.Номенклатура.UniqueID.UGuid},
                    {"col_d7", record.ХарактеристикаНоменклатури.UniqueID.UGuid},
                    {"col_a1", record.Серія.UniqueID.UGuid},
                    {"col_d8", record.Пакування.UniqueID.UGuid},
                    {"col_d9", record.КількістьУпаковок},
                    {"col_e1", record.Кількість},
                    {"col_e2", record.Ціна},
                    {"col_e3", record.Сума},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Номенклатура = original.Номенклатура.Copy(),
                    ХарактеристикаНоменклатури = original.ХарактеристикаНоменклатури.Copy(),
                    Серія = original.Серія.Copy(),
                    Пакування = original.Пакування.Copy(),
                    КількістьУпаковок = original.КількістьУпаковок,
                    Кількість = original.Кількість,
                    Ціна = original.Ціна,
                    Сума = original.Сума,
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public Довідники.Номенклатура_Pointer Номенклатура { get; set; } = new Довідники.Номенклатура_Pointer();
            public Довідники.ХарактеристикиНоменклатури_Pointer ХарактеристикаНоменклатури { get; set; } = new Довідники.ХарактеристикиНоменклатури_Pointer();
            public Довідники.СеріїНоменклатури_Pointer Серія { get; set; } = new Довідники.СеріїНоменклатури_Pointer();
