        {
            ПсуванняТоварів_Object copy = new()
            {
                Назва = Назва,
                НомерДок = НомерДок,
                ДатаДок = ДатаДок,
                Організація = Організація.Copy(),
                Підрозділ = Підрозділ.Copy(),
                Склад = Склад.Copy(),
                Причина = Причина,
                СумаДокументу = СумаДокументу,
                Коментар = Коментар,
                Автор = Автор.Copy(),
                КлючовіСловаДляПошуку = КлючовіСловаДляПошуку,
                Основа = Основа.Copy(),
                
            };
            
            if (copyTableParts)
            {
            
                //Товари - Таблична частина
                await Товари_TablePart.Read();
