    public class РахунокФактура_Pointer : DocumentPointer
    {
        public РахунокФактура_Pointer() : base(Config.Kernel, "tab_b10", РахунокФактура_Const.TYPE) => base.Init(new UniqueID());
        public РахунокФактура_Pointer(object? uid) : base(Config.Kernel, "tab_b10", РахунокФактура_Const.TYPE) => base.Init(new UniqueID(uid));
        public РахунокФактура_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_b10", РахунокФактура_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public РахунокФактура_Pointer(UniqueID uid) : base(Config.Kernel, "tab_b10", РахунокФактура_Const.TYPE) => base.Init(uid);
        public РахунокФактура_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_b10", РахунокФактура_Const.TYPE) => base.Init(uid, fields);
        public РахунокФактура_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_b10", РахунокФактура_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(РахунокФактура_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [РахунокФактура_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{РахунокФактура_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(РахунокФактура_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            РахунокФактура_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            РахунокФактура_Object? obj = await GetDocumentObject();
            if (obj != null) await obj.ClearSpendTheDocument();
                
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.ВільніЗалишки_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          
        public async Task SetDeletionLabel(bool label = true)
        {
          РахунокФактура_Object? obj = await GetDocumentObject();
            if (obj == null) return;
            
            if (label) await obj.ClearSpendTheDocument();
            
          await base.BaseDeletionLabel(label);
        }
        public РахунокФактура_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public РахунокФактура_Pointer GetEmptyPointer() => new();
        public async Task<РахунокФактура_Object?> GetDocumentObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            РахунокФактура_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
    }

    public class РахунокФактура_Select : DocumentSelect
    {		
        public РахунокФактура_Select() : base(Config.Kernel, "tab_b10") { }
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new РахунокФактура_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public РахунокФактура_Pointer? Current { get; private set; }

        public async Task<РахунокФактура_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new РахунокФактура_Pointer(pointer) : new РахунокФактура_Pointer();
        }
        
        public async Task<List<РахунокФактура_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<РахунокФактура_Pointer> documentPointerList = [];
            foreach (var documentPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                documentPointerList.Add(new РахунокФактура_Pointer(documentPointer.UniqueID, documentPointer.Fields));
            return documentPointerList;
        }
    }

      
    
    public class РахунокФактура_Товари_TablePart : DocumentTablePart
    {
        public РахунокФактура_Товари_TablePart(РахунокФактура_Object owner) : base(Config.Kernel, "tab_b11",
             ["col_a2", "col_b9", "col_c1", "col_c2", "col_c3", "col_c4", "col_c5", "col_c6", "col_c7", "col_c8", "col_a1", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_b11";
        
        public const string НомерРядка = "col_a2";
        public const string Номенклатура = "col_b9";
        public const string ХарактеристикаНоменклатури = "col_c1";
        public const string Пакування = "col_c2";
        public const string КількістьУпаковок = "col_c3";
        public const string Кількість = "col_c4";
        public const string ВидЦіни = "col_c5";
        public const string Ціна = "col_c6";
        public const string Сума = "col_c7";
        public const string Скидка = "col_c8";
        public const string Склад = "col_a1";

        public РахунокФактура_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.Номенклатура_Pointer.GetJoin(QuerySelect, Номенклатура, $"{TABLE}", "join_tab_2", "Номенклатура");
                  
                      /* pointer */
                      Довідники.ХарактеристикиНоменклатури_Pointer.GetJoin(QuerySelect, ХарактеристикаНоменклатури, $"{TABLE}", "join_tab_3", "ХарактеристикаНоменклатури");
                  
                      /* pointer */
                      Довідники.ПакуванняОдиниціВиміру_Pointer.GetJoin(QuerySelect, Пакування, $"{TABLE}", "join_tab_4", "Пакування");
                  
                      /* pointer */
                      Довідники.ВидиЦін_Pointer.GetJoin(QuerySelect, ВидЦіни, $"{TABLE}", "join_tab_7", "ВидЦіни");
                  
                      /* pointer */
                      Довідники.Склади_Pointer.GetJoin(QuerySelect, Склад, $"{TABLE}", "join_tab_11", "Склад");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_a2"] != DBNull.Value) ? (int)fieldValue["col_a2"] : 0,
                    Номенклатура = new Довідники.Номенклатура_Pointer(fieldValue["col_b9"]),
                    ХарактеристикаНоменклатури = new Довідники.ХарактеристикиНоменклатури_Pointer(fieldValue["col_c1"]),
                    Пакування = new Довідники.ПакуванняОдиниціВиміру_Pointer(fieldValue["col_c2"]),
                    КількістьУпаковок = (fieldValue["col_c3"] != DBNull.Value) ? (int)fieldValue["col_c3"] : 0,
                    Кількість = (fieldValue["col_c4"] != DBNull.Value) ? (decimal)fieldValue["col_c4"] : 0,
                    ВидЦіни = new Довідники.ВидиЦін_Pointer(fieldValue["col_c5"]),
                    Ціна = (fieldValue["col_c6"] != DBNull.Value) ? (decimal)fieldValue["col_c6"] : 0,
                    Сума = (fieldValue["col_c7"] != DBNull.Value) ? (decimal)fieldValue["col_c7"] : 0,
                    Скидка = (fieldValue["col_c8"] != DBNull.Value) ? (decimal)fieldValue["col_c8"] : 0,
                    Склад = new Довідники.Склади_Pointer(fieldValue["col_a1"]),
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.Номенклатура.Name = ItemValue["Номенклатура"];
                      record.ХарактеристикаНоменклатури.Name = ItemValue["ХарактеристикаНоменклатури"];
                      record.Пакування.Name = ItemValue["Пакування"];
                      record.ВидЦіни.Name = ItemValue["ВидЦіни"];
                      record.Склад.Name = ItemValue["Склад"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_b10"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a2", record.НомерРядка},
                    {"col_b9", record.Номенклатура.UniqueID.UGuid},
                    {"col_c1", record.ХарактеристикаНоменклатури.UniqueID.UGuid},
                    {"col_c2", record.Пакування.UniqueID.UGuid},
                    {"col_c3", record.КількістьУпаковок},
                    {"col_c4", record.Кількість},
                    {"col_c5", record.ВидЦіни.UniqueID.UGuid},
                    {"col_c6", record.Ціна},
                    {"col_c7", record.Сума},
                    {"col_c8", record.Скидка},
                    {"col_a1", record.Склад.UniqueID.UGuid},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Номенклатура = original.Номенклатура.Copy(),
                    ХарактеристикаНоменклатури = original.ХарактеристикаНоменклатури.Copy(),
                    Пакування = original.Пакування.Copy(),
                    КількістьУпаковок = original.КількістьУпаковок,
                    Кількість = original.Кількість,
                    ВидЦіни = original.ВидЦіни.Copy(),
                    Ціна = original.Ціна,
                    Сума = original.Сума,
                    Скидка = original.Скидка,
                    Склад = original.Склад.Copy(),
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public Довідники.Номенклатура_Pointer Номенклатура { get; set; } = new Довідники.Номенклатура_Pointer();
            public Довідники.ХарактеристикиНоменклатури_Pointer ХарактеристикаНоменклатури { get; set; } = new Довідники.ХарактеристикиНоменклатури_Pointer();
