             ["docname", "docdate", "docnomer", "col_a1", "col_a2", "col_a3", "col_a4", "col_a5", "col_a6", "col_a7", "col_a8", ], true)
        {
            
                //Табличні частини
                Товари_TablePart = new РозміщенняТоварівНаСкладі_Товари_TablePart(this);
                
