        {
          
            if (label)
            {
                await ClearRegAccum();
                await BaseSpend(false, DateTime.MinValue);
            }
            
          await base.BaseDeletionLabel(label);
        }
        public ЗбіркаТоварівНаСкладі_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
