    public class РозміщенняНоменклатуриПоКоміркам_Pointer : DocumentPointer
    {
        public РозміщенняНоменклатуриПоКоміркам_Pointer() : base(Config.Kernel, "tab_b29", РозміщенняНоменклатуриПоКоміркам_Const.TYPE) => base.Init(new UniqueID());
        public РозміщенняНоменклатуриПоКоміркам_Pointer(object? uid) : base(Config.Kernel, "tab_b29", РозміщенняНоменклатуриПоКоміркам_Const.TYPE) => base.Init(new UniqueID(uid));
        public РозміщенняНоменклатуриПоКоміркам_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_b29", РозміщенняНоменклатуриПоКоміркам_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public РозміщенняНоменклатуриПоКоміркам_Pointer(UniqueID uid) : base(Config.Kernel, "tab_b29", РозміщенняНоменклатуриПоКоміркам_Const.TYPE) => base.Init(uid);
        public РозміщенняНоменклатуриПоКоміркам_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_b29", РозміщенняНоменклатуриПоКоміркам_Const.TYPE) => base.Init(uid, fields);
        public РозміщенняНоменклатуриПоКоміркам_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_b29", РозміщенняНоменклатуриПоКоміркам_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(РозміщенняНоменклатуриПоКоміркам_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [РозміщенняНоменклатуриПоКоміркам_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{РозміщенняНоменклатуриПоКоміркам_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(РозміщенняНоменклатуриПоКоміркам_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            РозміщенняНоменклатуриПоКоміркам_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            
            await ClearRegAccum();
            await BaseSpend(false, DateTime.MinValue);
                
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        
        /* Очищення регістрів накопичення */
        Task ClearRegAccum() => Task.CompletedTask;
        public async Task SetDeletionLabel(bool label = true)
        {
          
            if (label)
            {
                await ClearRegAccum();
                await BaseSpend(false, DateTime.MinValue);
            }
            
          await base.BaseDeletionLabel(label);
        }
        public РозміщенняНоменклатуриПоКоміркам_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public РозміщенняНоменклатуриПоКоміркам_Pointer GetEmptyPointer() => new();
        public async Task<РозміщенняНоменклатуриПоКоміркам_Object?> GetDocumentObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            РозміщенняНоменклатуриПоКоміркам_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
    }

    public class РозміщенняНоменклатуриПоКоміркам_Select : DocumentSelect
    {		
        public РозміщенняНоменклатуриПоКоміркам_Select() : base(Config.Kernel, "tab_b29") { }
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new РозміщенняНоменклатуриПоКоміркам_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public РозміщенняНоменклатуриПоКоміркам_Pointer? Current { get; private set; }

        public async Task<РозміщенняНоменклатуриПоКоміркам_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new РозміщенняНоменклатуриПоКоміркам_Pointer(pointer) : new РозміщенняНоменклатуриПоКоміркам_Pointer();
        }
        
        public async Task<List<РозміщенняНоменклатуриПоКоміркам_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<РозміщенняНоменклатуриПоКоміркам_Pointer> documentPointerList = [];
            foreach (var documentPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                documentPointerList.Add(new РозміщенняНоменклатуриПоКоміркам_Pointer(documentPointer.UniqueID, documentPointer.Fields));
            return documentPointerList;
        }
    }

      
    
    public class РозміщенняНоменклатуриПоКоміркам_Товари_TablePart : DocumentTablePart
    {
        public РозміщенняНоменклатуриПоКоміркам_Товари_TablePart(РозміщенняНоменклатуриПоКоміркам_Object owner) : base(Config.Kernel, "tab_b32",
             ["col_a1", "col_h1", "col_a2", "col_h3", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_b32";
        
        public const string НомерРядка = "col_a1";
        public const string Номенклатура = "col_h1";
        public const string Комірка = "col_a2";
        public const string Пакування = "col_h3";

        public РозміщенняНоменклатуриПоКоміркам_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.Номенклатура_Pointer.GetJoin(QuerySelect, Номенклатура, $"{TABLE}", "join_tab_2", "Номенклатура");
                  
                      /* pointer */
                      Довідники.СкладськіКомірки_Pointer.GetJoin(QuerySelect, Комірка, $"{TABLE}", "join_tab_3", "Комірка");
                  
                      /* pointer */
                      Довідники.ПакуванняОдиниціВиміру_Pointer.GetJoin(QuerySelect, Пакування, $"{TABLE}", "join_tab_4", "Пакування");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_a1"] != DBNull.Value) ? (int)fieldValue["col_a1"] : 0,
                    Номенклатура = new Довідники.Номенклатура_Pointer(fieldValue["col_h1"]),
                    Комірка = new Довідники.СкладськіКомірки_Pointer(fieldValue["col_a2"]),
                    Пакування = new Довідники.ПакуванняОдиниціВиміру_Pointer(fieldValue["col_h3"]),
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.Номенклатура.Name = ItemValue["Номенклатура"];
                      record.Комірка.Name = ItemValue["Комірка"];
                      record.Пакування.Name = ItemValue["Пакування"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_b29"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a1", record.НомерРядка},
                    {"col_h1", record.Номенклатура.UniqueID.UGuid},
                    {"col_a2", record.Комірка.UniqueID.UGuid},
                    {"col_h3", record.Пакування.UniqueID.UGuid},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Номенклатура = original.Номенклатура.Copy(),
                    Комірка = original.Комірка.Copy(),
                    Пакування = original.Пакування.Copy(),
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public Довідники.Номенклатура_Pointer Номенклатура { get; set; } = new Довідники.Номенклатура_Pointer();
            public Довідники.СкладськіКомірки_Pointer Комірка { get; set; } = new Довідники.СкладськіКомірки_Pointer();
            public Довідники.ПакуванняОдиниціВиміру_Pointer Пакування { get; set; } = new Довідники.ПакуванняОдиниціВиміру_Pointer();
            
        }
    }
      
    
