        public bool ВідобразитиВБухгалтерськомуОбліку { get; set; } = false;
        
        //Табличні частини
        public КорегуванняБоргу_РозрахункиЗКонтрагентами_TablePart РозрахункиЗКонтрагентами_TablePart { get; set; }
        public КорегуванняБоргу_Проводки_TablePart Проводки_TablePart { get; set; }
        
    }
    
    public class КорегуванняБоргу_Pointer : DocumentPointer
    {
        public КорегуванняБоргу_Pointer() : base(Config.Kernel, "tab_a65", КорегуванняБоргу_Const.TYPE) => base.Init(new UniqueID());
        public КорегуванняБоргу_Pointer(object? uid) : base(Config.Kernel, "tab_a65", КорегуванняБоргу_Const.TYPE) => base.Init(new UniqueID(uid));
        public КорегуванняБоргу_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_a65", КорегуванняБоргу_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public КорегуванняБоргу_Pointer(UniqueID uid) : base(Config.Kernel, "tab_a65", КорегуванняБоргу_Const.TYPE) => base.Init(uid);
        public КорегуванняБоргу_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_a65", КорегуванняБоргу_Const.TYPE) => base.Init(uid, fields);
        public КорегуванняБоргу_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_a65", КорегуванняБоргу_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(КорегуванняБоргу_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [КорегуванняБоргу_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{КорегуванняБоргу_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(КорегуванняБоргу_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            КорегуванняБоргу_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            КорегуванняБоргу_Object? obj = await GetDocumentObject();
            if (obj != null) await obj.ClearSpendTheDocument();
                
        }
        public async Task<bool?> GetDeletionLabel() => await base.BaseGetDeletionLabel();
        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.РозрахункиЗКлієнтами_RecordsSet().Delete(this.UniqueID.UGuid);
              
                await new РегістриНакопичення.РозрахункиЗПостачальниками_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          
        public async Task SetDeletionLabel(bool label = true)
        {
          КорегуванняБоргу_Object? obj = await GetDocumentObject();
            if (obj == null) return;
            
            if (label) await obj.ClearSpendTheDocument();
            
          await base.BaseDeletionLabel(label);
        }
        public КорегуванняБоргу_Pointer Copy() => new(base.UniqueID, base.Fields, Name);
        public КорегуванняБоргу_Pointer GetEmptyPointer() => new();
        public async Task<КорегуванняБоргу_Object?> GetDocumentObject(bool readAllTablePart = false)
        {
            if (this.IsEmpty()) return null;
            КорегуванняБоргу_Object obj = new();
            return await obj.Read(base.UniqueID, readAllTablePart) ? obj : null;
        }
    }

    public class КорегуванняБоргу_Select : DocumentSelect
    {		
        public КорегуванняБоргу_Select() : base(Config.Kernel, "tab_a65") { }
        public async Task<bool> Select() => await base.BaseSelect();
        public async Task<bool> SelectSingle() { if (await base.BaseSelectSingle()) { MoveNext(); return true; } else { Current = null; return false; } }
        public bool MoveNext() { if (base.MoveToPosition() && base.CurrentPointerPosition.HasValue) { Current = new КорегуванняБоргу_Pointer(base.CurrentPointerPosition.Value.UniqueID, base.CurrentPointerPosition.Value.Fields); return true; } else { Current = null; return false; } }
        public КорегуванняБоргу_Pointer? Current { get; private set; }

        public async Task<КорегуванняБоргу_Pointer> FindByField(string name, object value, string funcToField = "", string funcToField_Param1 = "")
        {
            UniqueID? pointer = await base.BaseFindByField(name, value, funcToField, funcToField_Param1);
            return pointer != null ? new КорегуванняБоргу_Pointer(pointer) : new КорегуванняБоргу_Pointer();
        }
        
        public async Task<List<КорегуванняБоргу_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
            List<КорегуванняБоргу_Pointer> documentPointerList = [];
            foreach (var documentPointer in await base.BaseFindListByField(name, value, limit, offset)) 
                documentPointerList.Add(new КорегуванняБоргу_Pointer(documentPointer.UniqueID, documentPointer.Fields));
            return documentPointerList;
        }
    }

      
    
    public class КорегуванняБоргу_РозрахункиЗКонтрагентами_TablePart : DocumentTablePart
    {
        public КорегуванняБоргу_РозрахункиЗКонтрагентами_TablePart(КорегуванняБоргу_Object owner) : base(Config.Kernel, "tab_b12",
             ["col_a1", "col_e9", "col_f1", "col_f2", "col_a2", ], true)
        {
            if (owner == null) throw new Exception("owner null");
            Owner = owner;
            
            QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
            
        }

        public const string TABLE = "tab_b12";
        
        public const string НомерРядка = "col_a1";
        public const string Контрагент = "col_e9";
        public const string Валюта = "col_f1";
        public const string Сума = "col_f2";
        public const string ТипКонтрагента = "col_a2";

        public КорегуванняБоргу_Object Owner { get; private set; }
        
        public List<Record> Records { get; set; } = [];

        public event EventHandler? Saved;
        
        public void FillJoin(string[]? orderFields = null)
        {
            QuerySelect.Clear();

            if (orderFields != null)
            {
              foreach(string field in orderFields)
                QuerySelect.Order.Add(field, SelectOrder.ASC);
            }
            
            else
            { 
              QuerySelect.Order.Add(НомерРядка, SelectOrder.ASC);
              
            }
            
                      /* pointer */
                      Довідники.Контрагенти_Pointer.GetJoin(QuerySelect, Контрагент, $"{TABLE}", "join_tab_2", "Контрагент");
                  
                      /* pointer */
                      Довідники.Валюти_Pointer.GetJoin(QuerySelect, Валюта, $"{TABLE}", "join_tab_3", "Валюта");
                  
        }

        public async Task Read()
        {
            Records.Clear();
            await base.BaseRead(Owner.UniqueID);

            foreach (Dictionary<string, object> fieldValue in base.FieldValueList) 
            {
                Record record = new()
                {
                    UID = (Guid)fieldValue["uid"],
                    НомерРядка = (fieldValue["col_a1"] != DBNull.Value) ? (int)fieldValue["col_a1"] : 0,
                    Контрагент = new Довідники.Контрагенти_Pointer(fieldValue["col_e9"]),
                    Валюта = new Довідники.Валюти_Pointer(fieldValue["col_f1"]),
                    Сума = (fieldValue["col_f2"] != DBNull.Value) ? (decimal)fieldValue["col_f2"] : 0,
                    ТипКонтрагента = (fieldValue["col_a2"] != DBNull.Value) ? (Перелічення.ТипиКонтрагентів)fieldValue["col_a2"] : 0,
                    
                };
                Records.Add(record);
                
                if (JoinValue.TryGetValue(record.UID.ToString(), out var ItemValue))
                {
                  record.JoinItemValue = ItemValue;
                  record.Контрагент.Name = ItemValue["Контрагент"];
                      record.Валюта.Name = ItemValue["Валюта"];
                      
                }
                
            }
            
            base.BaseClear();
        }
        
        public async Task Save(bool clear_all_before_save) 
        {
            if (!await base.IsExistOwner(Owner.UniqueID, "tab_a65"))
                throw new Exception("Owner not exist");
            
            base.OwnerVersionID = Owner.VersionID;
            base.OwnerBasis = Owner.GetBasis();
            Dictionary<Guid, Dictionary<string, object>> listFieldValue = [];
            

            await base.BaseBeginTransaction();
            
            if (clear_all_before_save)
                await base.BaseDelete(Owner.UniqueID);

            
            int sequenceNumber_НомерРядка = 0;
            
            foreach (Record record in Records)
            {
                
                record.НомерРядка = ++sequenceNumber_НомерРядка;
                
                Dictionary<string, object> fieldValue = new()
                {
                    {"col_a1", record.НомерРядка},
                    {"col_e9", record.Контрагент.UniqueID.UGuid},
                    {"col_f1", record.Валюта.UniqueID.UGuid},
                    {"col_f2", record.Сума},
                    {"col_a2", (int)record.ТипКонтрагента},
                    
                };
                record.UID = await base.BaseSave(record.UID, Owner.UniqueID, fieldValue);
                
                listFieldValue.Add(record.UID, fieldValue);
                
            }
            
            await base.BaseCommitTransaction();
            
            await base.BaseSaveVersion(listFieldValue);
            
            Saved?.Invoke(this, new EventArgs());
        }

        public List<Record> Copy()
        {
            int count = Records.Count;
            List<Record> copy = new(count);
            for (int i = 0; i < count; i++)
            {
                Record original = Records[i];
                copy.Add(new()
                {
                    НомерРядка = original.НомерРядка,
                    Контрагент = original.Контрагент.Copy(),
                    Валюта = original.Валюта.Copy(),
                    Сума = original.Сума,
                    ТипКонтрагента = original.ТипКонтрагента,
                     
                });
            }

            return copy;
        }

        public class Record : DocumentTablePartRecord
        {
            public int НомерРядка { get; set; } = 0;
            public Довідники.Контрагенти_Pointer Контрагент { get; set; } = new Довідники.Контрагенти_Pointer();
            public Довідники.Валюти_Pointer Валюта { get; set; } = new Довідники.Валюти_Pointer();
            public decimal Сума { get; set; } = 0;
            public Перелічення.ТипиКонтрагентів ТипКонтрагента { get; set; } = 0;
            
        }
    }
      
    
