            return pointer != null ? new ЧекККМ_Pointer(pointer) : new ЧекККМ_Pointer();
        }
        
        public async Task<List<ЧекККМ_Pointer>> FindListByField(string name, object value, int limit = 0, int offset = 0)
        {
