    public class Амортизація_Object : DocumentObject
    {
        public Амортизація_Object() : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE,
             ["docname", "docnomer", "docdate", "col_a1", "col_a2", "col_a3", "col_a4", "col_a5", "col_a6", ])
        {
            
        }
        
        public async Task New()
        {
            BaseNew();
            Caption = Амортизація_Const.FULLNAME + " *";
            
                await Амортизація_Triggers.New(this);
              
        }

        public async Task<bool> Read(UniqueID uid, bool readAllTablePart = false)
        {
            if (await BaseRead(uid))
            {
                Назва = base.FieldValue["docname"].ToString() ?? "";
                НомерДок = base.FieldValue["docnomer"].ToString() ?? "";
                ДатаДок = (base.FieldValue["docdate"] != DBNull.Value) ? DateTime.Parse(base.FieldValue["docdate"].ToString() ?? DateTime.MinValue.ToString()) : DateTime.MinValue;
                Коментар = base.FieldValue["col_a1"].ToString() ?? "";
                Основа = (base.FieldValue["col_a2"] != DBNull.Value) ? (UuidAndText)base.FieldValue["col_a2"] : new UuidAndText();
                Організація = new Довідники.Організації_Pointer(base.FieldValue["col_a3"]);
                Автор = new Довідники.Користувачі_Pointer(base.FieldValue["col_a4"]);
                ДокументБухгалтерськаОперація = new Документи.БухгалтерськаОперація_Pointer(base.FieldValue["col_a5"]);
                ВідобразитиВБухгалтерськомуОбліку = (base.FieldValue["col_a6"] != DBNull.Value) ? (bool)base.FieldValue["col_a6"] : false;
                
                BaseClear();
                
                Caption = string.Join(", ", [Назва, ]);
                return true;
            }
            else
                return false;
        }
        
        public async Task<bool> Save()
        {
            
                await Амортизація_Triggers.BeforeSave(this);
            base.FieldValue["docname"] = Назва;
            base.FieldValue["docnomer"] = НомерДок;
            base.FieldValue["docdate"] = ДатаДок;
            base.FieldValue["col_a1"] = Коментар;
            base.FieldValue["col_a2"] = Основа;
            base.FieldValue["col_a3"] = Організація.UniqueID.UGuid;
            base.FieldValue["col_a4"] = Автор.UniqueID.UGuid;
            base.FieldValue["col_a5"] = ДокументБухгалтерськаОперація.UniqueID.UGuid;
            base.FieldValue["col_a6"] = ВідобразитиВБухгалтерськомуОбліку;
            
            bool result = await BaseSave();
            if (result)
            {
                
            }
            Caption = string.Join(", ", [Назва, ]);
            return result;
        }

        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            
            await BaseAddIgnoreDocumentList();
            bool spend = await Амортизація_SpendTheDocument.Spend(this);
            if (!spend) await ClearRegAccum();
            await BaseSpend(spend, spend ? spendDate : DateTime.MinValue);
            await BaseRemoveIgnoreDocumentList();
            return spend;
                
        }

        
        /* Очищення регістрів накопичення */
        
        async Task ClearRegAccum()
        {
            if(!this.UniqueID.IsEmpty())
            {
              
                await new РегістриНакопичення.БухгалтерськіОперації_RecordsSet().Delete(this.UniqueID.UGuid);
              
            }
        }
          

        public async Task ClearSpendTheDocument()
        {
            await ClearRegAccum();
            
            await Амортизація_SpendTheDocument.Clear(this);
            
            await BaseSpend(false, DateTime.MinValue);
        }

        public async Task<Амортизація_Object> Copy(bool copyTableParts = false)
        {
            Амортизація_Object copy = new()
            {
                Назва = Назва,
                НомерДок = НомерДок,
                ДатаДок = ДатаДок,
                Коментар = Коментар,
                Основа = Основа.Copy(),
                Організація = Організація.Copy(),
                Автор = Автор.Copy(),
                ДокументБухгалтерськаОперація = ДокументБухгалтерськаОперація.Copy(),
                ВідобразитиВБухгалтерськомуОбліку = ВідобразитиВБухгалтерськомуОбліку,
                
            };
            

            await copy.New();
            
                await Амортизація_Triggers.Copying(copy, this);      
            
            return copy;
        }

        public async Task SetDeletionLabel(bool label = true)
        {
            
            await ClearSpendTheDocument();
            await base.BaseDeletionLabel(label);
        }

        public async Task Delete()
        {
            
            await ClearSpendTheDocument();
            await base.BaseDelete([]);
        }
        
        public Амортизація_Pointer GetDocumentPointer() => new(UniqueID);
        public async Task<string> GetPresentation() => await base.BasePresentation(Амортизація_Const.PRESENTATION_FIELDS);
        
        public string Назва { get; set; } = "";
        public string НомерДок { get; set; } = "";
        public DateTime ДатаДок { get; set; } = DateTime.MinValue;
        public string Коментар { get; set; } = "";
        public UuidAndText Основа { get; set; } = new UuidAndText();
        public Довідники.Організації_Pointer Організація { get; set; } = new Довідники.Організації_Pointer();
        public Довідники.Користувачі_Pointer Автор { get; set; } = new Довідники.Користувачі_Pointer();
        public Документи.БухгалтерськаОперація_Pointer ДокументБухгалтерськаОперація { get; set; } = new Документи.БухгалтерськаОперація_Pointer();
        public bool ВідобразитиВБухгалтерськомуОбліку { get; set; } = false;
        
    }
    
    public class Амортизація_Pointer : DocumentPointer
    {
        public Амортизація_Pointer() : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE) => base.Init(new UniqueID());
        public Амортизація_Pointer(object? uid) : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE) => base.Init(new UniqueID(uid));
        public Амортизація_Pointer(object? uid, object? name) : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE) => base.Init(new UniqueID(uid), name?.ToString());
        public Амортизація_Pointer(UniqueID uid) : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE) => base.Init(uid);
        public Амортизація_Pointer(UniqueID uid, Dictionary<string, object>? fields) : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE) => base.Init(uid, fields);
        public Амортизація_Pointer(UniqueID uid, Dictionary<string, object>? fields, object? name) : base(Config.Kernel, "tab_b73", Амортизація_Const.TYPE) => base.Init(uid, fields, name?.ToString());
        public string Назва { get => Name; set => Name = value; }
        public async Task<string> GetPresentation() => Name = await base.BasePresentation(Амортизація_Const.PRESENTATION_FIELDS);
        public static void GetJoin(Query querySelect, string joinField, string parentTable, string joinTableAlias, string fieldAlias)
        {
            string[] presentationField = new string [Амортизація_Const.PRESENTATION_FIELDS.Length];
            for (int i = 0; i < presentationField.Length; i++) presentationField[i] = $"{joinTableAlias}.{Амортизація_Const.PRESENTATION_FIELDS[i]}";
            querySelect.Joins.Add(new Join(Амортизація_Const.TABLE, joinField, parentTable, joinTableAlias));
            querySelect.FieldAndAlias.Add(new ValueName<string>(presentationField.Length switch { 1 => presentationField[0], >1 => $"concat_ws (', ', " + string.Join(", ", presentationField) + ")", _ => "'#'" }, fieldAlias));
        }
        public async Task<bool?> IsSpend() => await base.BaseIsSpend();
        public async Task<(bool? Spend, DateTime SpendDate)> GetSpend() => await base.BaseGetSpend();
        public async Task<bool> SpendTheDocument(DateTime spendDate)
        {
            Амортизація_Object? obj = await GetDocumentObject();
            return obj != null && await obj.SpendTheDocument(spendDate);
        }
        public async Task ClearSpendTheDocument()
        {
            Амортизація_Object? obj = await GetDocumentObject();
            if (obj != null) await obj.ClearSpendTheDocument();
                
